const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };
const question = body.question || '';
if (!question || String(question).trim().length === 0) {
  return { json: { ok: false, status: 400, error: 'question required' } };
}
return { json: { token: token, question: String(question).trim().slice(0, 1000) } };

// Tenant gate. client_id MUST come from the validated session row,
// never from the request body — that's the cross-tenant isolation
// anchor. The session row also tells us the role; we allow client,
// team_member, advisor, supervisor, mga_principal.
const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.id || rows.user_id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
const allowedRoles = ['client', 'team_member', 'advisor', 'supervisor', 'mga_principal'];
if (allowedRoles.indexOf(row.user_role) === -1) {
  return { json: { ok: false, status: 403, error: 'Tenant access required' } };
}
if (!row.client_id) {
  return { json: { ok: false, status: 403, error: 'No client mapped to session' } };
}
const question = $('Extract Inputs').item.json.question;
return { json: { ok: true, client_id: row.client_id, user_role: row.user_role, question: question } };

// Converge parallel queries; build pre-baked tenant facts so Claude
// answers from grounded data instead of hallucinating. The system
// prompt tells Claude: read-only, scoped to this tenant, no SQL,
// no admin tools.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};
const leads = allOf('Query Leads');
const bookings = allOf('Query Bookings');
const clientArr = allOf('Query Client');
const client = clientArr[0] || {};

// Compute tenant facts
const now = Date.now();
const d7  = now - 7  * 24*60*60*1000;
const d30 = now - 30 * 24*60*60*1000;
const statusBuckets = { 'New Lead': 0, 'Contacted': 0, 'Replied': 0, 'Booked': 0, 'Closed Lost': 0 };
let new7 = 0, repl30 = 0, book30 = 0, contacted30 = 0;
leads.forEach(function (l) {
  const s = l.lead_status || 'New Lead';
  if (statusBuckets.hasOwnProperty(s)) statusBuckets[s] += 1;
  const created = l.date_created ? new Date(l.date_created).getTime() : 0;
  const sent    = l.outreach_sent_at ? new Date(l.outreach_sent_at).getTime() : 0;
  if (created >= d7) new7 += 1;
  if (sent >= d30) contacted30 += 1;
  if (s === 'Replied' && created >= d30) repl30 += 1;
  if (s === 'Booked'  && created >= d30) book30 += 1;
});
const upcoming = bookings.filter(function (b) {
  return b.scheduled_start && new Date(b.scheduled_start).getTime() > now;
}).slice(0, 5);

const question = $('Check Tenant').item.json.question;

const systemPrompt = [
  'You are the Crystallux Assistant for ' + (client.client_name || 'this customer') + '.',
  'You answer questions ABOUT THEIR PIPELINE ONLY. You do NOT have access to other clients data.',
  'Be concise: 1-3 sentences for direct questions, a short list for list questions (max 5 items).',
  'If the question is outside their pipeline (e.g. "what is Mary revenue?"), politely decline.',
  'Never produce SQL. Never invent numbers — use only the facts below.',
  '',
  'TENANT: ' + (client.client_name || '?'),
  'Industry: ' + (client.industry || client.vertical || '?'),
  'City: ' + (client.city || '?'),
  '',
  'PIPELINE FACTS (today):',
  '- Total leads: ' + leads.length,
  '- New in last 7 days: ' + new7,
  '- Contacted (last 30d): ' + contacted30,
  '- Replies (last 30d): ' + repl30,
  '- Booked (last 30d): ' + book30,
  '- Lead status mix: ' + JSON.stringify(statusBuckets),
  '- Upcoming bookings: ' + upcoming.length,
  upcoming.length ? '  Next: ' + upcoming.map(function(b){ return new Date(b.scheduled_start).toISOString().slice(0,16).replace('T',' '); }).join(', ') : ''
].filter(Boolean).join('\n');

return { json: {
  claude_payload: {
    model: 'claude-sonnet-4-5-20250929',
    max_tokens: 350,
    temperature: 0.2,
    system: systemPrompt,
    messages: [
      { role: 'user', content: question }
    ]
  }
} };

const claude = $input.item.json;
let answer = 'I could not generate an answer right now. Please try again in a moment.';
if (claude && Array.isArray(claude.content) && claude.content.length) {
  const first = claude.content.find(function (c) { return c.type === 'text'; });
  if (first && first.text) answer = String(first.text).trim();
} else if (claude && claude.error && claude.error.message) {
  answer = 'Assistant error: ' + claude.error.message + '. The platform admin can check Anthropic credentials.';
}
return { json: { ok: true, answer: answer } };
